import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"宝可梦综述","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/宝可梦综述.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/宝可梦综述.md"}'),o={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/宝可梦综述.md"};function d(b,e,_,l,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"宝可梦综述",tabindex:"-1"},[n("宝可梦综述 "),r("a",{class:"header-anchor",href:"#宝可梦综述","aria-label":'Permalink to "宝可梦综述"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘004D")])])],-1),s('<h1 id="宝可梦综述-1" tabindex="-1">宝可梦综述 <a class="header-anchor" href="#宝可梦综述-1" aria-label="Permalink to &quot;宝可梦综述&quot;">​</a></h1><p>宝可梦综述</p><p>宝可梦视为召唤物，每一只宝可梦都需要一个精灵球作为宝可梦的休息场所。<br> 宝可梦在购买时可花费额外750分购买一颗普通精灵球。<br> 你拥有的宝可梦等级不得超过你的训练家等级。</p><p>（ST选开）每次购买宝可梦时骰一个D10的机运骰，仅可以靠风度附加成功重骰，若通过，则该宝可梦为闪光版本，这不会带来任何能力变化，只会让你这一宝可梦外表变得金光闪闪，且可以称呼该宝可梦为闪光XXX</p><p>宝可梦的恢复方式<br> 将宝可梦收入普通精灵球中，当宝可梦处于精灵球中四小时就视为进行了一次长休，这一效果每日只会生效一次。<br> 宝可梦死亡后可以回收至精灵球中，经过完整的一日即可复活，复活后的宝可梦生命值为完好状态的一半。<br> 若无精灵球，则宝可梦视为持续跟在训练家身旁，在影片中死亡后则无法复活。</p><p>将宝可梦从精灵球中释放出来是一个迅捷动作，将宝可梦收回精灵球中是一个花招动作，释放/收回宝可梦的行动一轮只能各进行一次。<br> 释放宝可梦时可以将宝可梦释放在自身身周30米范围内的任意位置，回收宝可梦同样需要该宝可梦在你身周30米范围内。</p><p>特殊地，宝可梦死亡自动回归精灵球，此时回收距离为你的敏感范围。若超出此距离，则需要训练家移动到符合距离的范围内回收。<br> 使用伏特替换，急速折返，快速折返，接棒，瞬间移动技能时，回收距离等于技能射程/技能冲锋距离/技能移动距离。</p><p>宝可梦的装备<br> 宝可梦不能使用通常意义上的武器、护甲。<br> 宝可梦只有一个装备位，且只能装备宝可梦的专属道具。</p><p>宝可梦技能学习<br> 宝可梦可通过技能机器学习宝可梦专属的各属性宝可梦技能。非宝可梦不能学习与使用技能机器内的宝可梦技能。<br> 一个宝可梦可以在主神空间将它已习得的宝可梦技能传授给另一个满足学习条件的宝可梦，这需要7天的时间，一只宝可梦每一场影片只能进行一次传授或学习宝可梦技能。</p><p>宝可梦的指挥<br> 训练家能拥有任意只宝可梦，但只能携带至多6只宝可梦进入战斗。<br> 宝可梦是独立随从，具有自己的先攻顺位、迅捷/反射动作、移动动作、标准动作。但如果没有训练家的指挥，则这些动作只能进行基础规则中允许的行为。<br> 【指挥状态】：训练家可以自由动作与一名处于训练家周围30米内的宝可梦建立指挥状态，若如此做，则宝可梦在进行攻击时，会将训练家的指挥专业加入攻击检定。除非处于指挥状态的宝可梦回到精灵球内，否则训练家与宝可梦的指挥状态不能取消。</p><p>宝可梦技能的使用<br> 训练家能指挥宝可梦使用宝可梦技能，这需要训练家与宝可梦之间建立【指挥状态】。<br> 训练家需要先消耗除【宝可梦使用动作】以外的所有动作才能令宝可梦使用宝可梦技能。对于声明类技能，在声明动作发出时，就会立即消耗训练家的本轮的指挥动作。<br> 宝可梦在训练家消耗指挥动作以后，可在自己的回合消耗自己的动作使用对应的宝可梦技能。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',13)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
